(function() {
    const waitForSpicetify = setInterval(() => {
        if (typeof Spicetify !== 'undefined' && Spicetify.Player) {
            clearInterval(waitForSpicetify);
            initDog();
        }
    }, 500);
    function initDog() {
        const { React, ReactDOM } = Spicetify;
        
        const frames = [
            "data:image/gif;base64,",
            "data:image/gif;base64,",
            "data:image/gif;base64,",
            "data:image/gif;base64,",
            "data:image/gif;base64,",
            "data:image/gif;base64,",
            "data:image/gif;base64,",
            "data:image/gif;base64,",
            "data:image/gif;base64,",
            "data:image/gif;base64,",
            "data:image/gif;base64,"
        ];

function injectDog() {
        const target = document.querySelector(".main-nowPlayingBar-center");
        if (!target) return;
        if (document.getElementById("brazilian-dog-container")) return;

        const container = document.createElement("div");
        container.id = "brazilian-dog-container";
        container.style.position = "absolute";
        container.style.top = "-50px";
        container.style.left = "50%";
        container.style.transform = "translateX(-50%)";
        container.style.zIndex = "9999999";
        container.style.pointerEvents = "none";

        const img = document.createElement("img");
        img.src = frames[0];
        img.style.width = "40px";
        img.style.height = "40px";

        container.appendChild(img);
        target.style.position = "relative";
        target.appendChild(container);

        setInterval(() => {
            if (Spicetify.Player.data.isPaused) {
                img.src = frames[0];
            } else {
                img.src = frames[(Date.now() / 80) % frames.length | 0];
            }
        }, 80);
    }

    const checkReady = setInterval(() => {
        if (typeof Spicetify !== 'undefined' && Spicetify.Player) {
            clearInterval(checkReady);
            setInterval(injectDog, 1000);
        }
    }, 500);
}
})();